commands.cmd:
raw=$(systemctl list-timers --all -o json 2>/dev/null) || { echo "list-timers failed" >&2; exit 1; }
now_us=$(date +%s)000000
printf '%s' "$raw" | jq -c --argjson now "$now_us" '{
  results: map({
    unit: .unit,
    next_elapse_usec: (.next_elapse_realtime // 0),
    last_trigger_usec: (.last_trigger_usec // 0),
    last_trigger_age_sec: (if (.last_trigger_usec // 0) > 0 then (($now - .last_trigger_usec) / 1000000 | floor) else -1 end)
  })
}' || { echo "jq failed" >&2; exit 1; }
